parameters.jsCode:
return $input.all().map((item) => {
  // 원본 가사 안전하게 가져오기
  const rawText = item.json.output?.[0]?.content?.[0]?.text || "";

  // 가사 정리 (기존과 동일한 로직)
  const cleanedText = rawText
    .replace(/\[Lyrics\]:/g, "")
    .replace(/\n/g, " ")
    .trim();

  return {
    json: {
      ...item.json,     // ← 기존 데이터(아이디, Sound Type 등) 모두 유지!
      text: cleanedText // ← 정제된 가사 (이후 노드에서 그대로 {{ $json.text }} 사용 가능)
    }
  };
});

